{
  "model": "claude-sonnet-4-5",
  "max_tokens": 1024,
  "messages": [
    {
      "role": "user",
      "content": "You are an expert lead scoring AI for Cognflow, an n8n automation agency. Score the following lead and respond ONLY in this exact format with no extra text:

SCORE: [number 0-100]
TIER: [Hot or Warm or Cold]
QUALIFIED: [true or false]
INTENT: [one sentence]
SUGGESTED_SERVICE: [one sentence]
REASONING: [two to three sentences]

Lead details:
- Name: {{1.data.fields[1].value}}
- Business: {{1.data.fields[2].value}}
- Email: {{1.data.fields[3].value}}
- Budget: {{1.data.fields[4].value}}
- Pain Point: {{1.data.fields[5].value}}
- Source: {{1.data.fields[6].value}}"
    }
  ]
}
